MAX_CACHE_SIZE_BYTES = 50 * 1024 * 1024  # 50MB max per entry
MAX_KEY_LENGTH = 256


class DiskCache:
    """Thread-safe disk-based cache with msgpack serialization and TTL expiration."""

    def __init__(self, cache_dir: Path, default_ttl: int = DEFAULT_TTL):
        self._cache_dir = cache_dir.resolve()
        self._default_ttl = default_ttl
        self._lock = threading.Lock()
        self._ensure_cache_dir()

    def _ensure_cache_dir(self):
        """Create cache directory with restricted permissions."""
        self._cache_dir.mkdir(parents=True, exist_ok=True)
        os.chmod(self._cache_dir, 0o700)

    def _make_safe_key(self, key: str) -> str:
        """Generate a safe filesystem key from arbitrary input."""
        if not isinstance(key, str) or len(key) > MAX_KEY_LENGTH:
            raise ValueError("Invalid cache key")
        return hashlib.sha256(key.encode("utf-8")).hexdigest()

    def _get_cache_path(self, safe_key: str) -> Path:
        """Get the cache file path, ensuring it stays within cache directory."""
        cache_path = (self._cache_dir / safe_key).resolve()
        if not str(cache_path).startswith(str(self._cache_dir)):
            raise ValueError("Invalid cache path detected")
        return cache_path

    def get(self, key: str):
        """Retrieve a cached value if it exists and hasn't expired."""
        safe_key = self._make_safe_key(key)
        cache_path = self._get_cache_path(safe_key)

        with self._lock:
            if not cache_path.is_file():
                return None

            try:
                raw_data = cache_path.read_bytes()
                if len(raw_data) > MAX_CACHE_SIZE_BYTES:
                    self._safe_delete(cache_path)
                    return None

                entry = msgpack.unpackb(raw_data, raw=False, strict_map_key=True)

                if not isinstance(entry, dict) or "expires_at" not in entry or "data" not in entry:
                    self._safe_delete(cache_path)
                    return None

                expires_at = entry["expires_at"]
                if not isinstance(expires_at, (int, float)):
                    self._safe_delete(cache_path)
                    return None

                if time.time() > expires_at:
                    self._safe_delete(cache_path)
                    return None

                return entry["data"]

            except (msgpack.UnpackException, msgpack.ExtraData, ValueError, KeyError, TypeError):
                self._safe_delete(cache_path)
                return None

    def set(self, key: str, value, ttl: int = None):
        """Store a value in the cache with a TTL."""
        if ttl is None:
            ttl = self._default_ttl

        if not isinstance(ttl, int) or ttl <= 0:
            raise ValueError("TTL must be a positive integer")

        safe_key = self._make_safe_key(key)
        cache_path = self._get_cache_path(safe_key)

        entry = {
            "data": value,
            "created_at": time.time(),
            "expires_at": time.time() + ttl,
        }

        try:
            serialized = msgpack.packb(entry, use_bin_type=True)
        except (TypeError, ValueError) as e:
            raise ValueError(f"Data is not serializable: {e}")

        if len(serialized) > MAX_CACHE_SIZE_BYTES:
            raise ValueError("Serialized data exceeds maximum cache entry size")

        with self._lock:
            temp_path = cache_path.with_suffix(".tmp")
            try:
                temp_path.write_bytes(serialized)
                os.chmod(temp_path, 0o600)
                temp_path.rename(cache_path)
            except OSError:
                self._safe_delete(temp_path)
                raise

    def delete(self, key: str) -> bool:
        """Delete a cached entry."""
        safe_key = self._make_safe_key(key)
        cache_path = self._get_cache_path(safe_key)

        with self._lock:
            return self._safe_delete(cache_path)

    def clear(self) -> int:
        """Clear all cache entries. Returns count of deleted entries."""
        count = 0
        with self._lock:
            for cache_file in self._cache_dir.iterdir():
                resolved = cache_file.resolve()
                if str(resolved).startswith(str(self._cache_dir)) and resolved.is_file():
                    if self._safe_delete(resolved):
                        count += 1
        return count

    def cleanup_expired(self) -> int:
        """Remove all expired entries. Returns count of deleted entries."""
        count = 0
        now = time.time()

        with self._lock:
            for cache_file in self._cache_dir.iterdir():
                resolved = cache_file.resolve()
                if not str(resolved).startswith(str(self._cache_dir)):
                    continue
                if not resolved.is_file():
                    continue
                if resolved.suffix == ".tmp":
                    self._safe_delete(resolved)
                    count += 1
                    continue

                try:
                    raw_data = resolved.read_bytes()
                    entry = msgpack.unpackb(raw_data, raw=False, strict_map_key=True)
                    if not isinstance(entry, dict) or "expires_at" not in entry:
                        self._safe_delete(resolved)
                        count += 1
                    elif now > entry["expires_at"]:
                        self._safe_delete(resolved)
                        count += 1
                except (msgpack.UnpackException, msgpack.ExtraData, OSError, TypeError):
                    self._safe_delete(resolved)
                    count += 1

        return count

    def _safe_delete(self, path: Path) -> bool:
        """Safely delete a file."""
        try:
            path.unlink(missing_ok=True)
            return True
        except OSError:
            return False


# Initialize the cache
cache = DiskCache(CACHE_DIR, DEFAULT_TTL)


def cached_response(ttl: int = None, key_prefix: str = ""):
    """Decorator to cache Flask route responses."""

    def decorator(f):
        @wraps(f)
        def wrapper(*args, **kwargs):
            # Build cache key from request method, path, query string, and relevant kwargs
            key_parts = [
                key_prefix,
                request.method,
                request.path,
                request.query_string.decode("utf-8", errors="replace"),
            ]
            # Include route kwargs in key
            for k, v in sorted(kwargs.items()):
                key_parts.append(f"{k}={v}")

            cache_key = "|".join(key_parts)

            cached = cache.get(cache_key)
            if cached is not None:
                response = jsonify(cached)
                response.headers["X-Cache"] = "HIT"
                return response

            result = f(*args, **kwargs)

            # If the function returns a tuple (data, status_code), handle it
            if isinstance(result, tuple):
                data, status_code = result[0], result[1]
                if status_code == 200 and isinstance(data, dict):
                    cache.set(cache_key, data, ttl=ttl)
                    response = jsonify(data)
                    response.headers["X-Cache"] = "MISS"
                    return response, status_code
                return result

            if isinstance(result, dict):
                cache.set(cache_key, result, ttl=ttl)
                response = jsonify(result)
                response.headers["X-Cache"] = "MISS"
                return response

            return result

        return wrapper

    return decorator


